window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-air-brakes"] = window.COURSE_LANG["cdl-air-brakes"] || {};
window.COURSE_LANG["cdl-air-brakes"]["es"] = [
  {"id":1,"q":"La bomba que llena los tanques de aire es:","opts":["El gobernador","El ajustador de holgura","La cámara de freno","El compresor de aire"],"re":"El compresor de aire bombea aire a los tanques de almacenamiento (depósitos)."},
  {"id":2,"q":"Los depósitos (tanques) de aire deben drenarse de:","opts":["Líquido de frenos","Refrigerante del motor","Agua y aceite acumulados","Refrigerante de aire acondicionado"],"re":"Drena el agua y el aceite del compresor a diario para que no reduzcan el frenado ni se congelen."},
  {"id":3,"q":"El dispositivo que quita la humedad del aire antes de los tanques es:","opts":["El secador de aire (air dryer)","La válvula de pie","La leva en S","El gobernador"],"re":"Un secador de aire quita el agua y algo de aceite del aire comprimido."},
  {"id":4,"q":"El pedal de freno en un vehículo con frenos de aire también se llama:","opts":["Ajustador de holgura","Gobernador","Válvula de protección del tractor","Válvula de pie (treadle)"],"re":"Pisar la válvula de pie (treadle) envía aire a los frenos; pisar más fuerte aplica más."},
  {"id":5,"q":"Dentro de la cámara de freno, la presión de aire empuja:","opts":["El eje motriz","El brazo de dirección","Una varilla (push rod) conectada al ajustador de holgura","Una varilla de combustible"],"re":"El aire mueve la varilla, que gira el ajustador de holgura y la leva en S para aplicar los frenos."},
  {"id":6,"q":"La función de la leva en S (S-cam) es:","opts":["Bombear aire","Medir la presión","Empujar las zapatas contra el tambor","Enfriar el motor"],"re":"Cuando el ajustador gira la leva en S, separa las zapatas contra el tambor de freno."},
  {"id":7,"q":"Pisar el pedal de freno más fuerte:","opts":["No usa aire extra","Aplica más aire y más frenado, pero usa más aire","Suelta los frenos","Bombea los tanques"],"re":"Más pedal es más presión y más frenado, pero baja la presión de los tanques más rápido."},
  {"id":8,"q":"¿Qué tipo de frenos de base usa la mayoría de los vehículos pesados?","opts":["Solo de disco","Sin frenos en el eje trasero","De banda","De tambor con leva en S"],"re":"Los frenos de tambor con leva en S son los más comunes en vehículos pesados."},
  {"id":9,"q":"El gobernador controla:","opts":["La radio","El esfuerzo de dirección","La mezcla de combustible","Cuándo el compresor bombea aire a los tanques"],"re":"El gobernador inicia (cut-in) y detiene (cut-out) el bombeo del compresor a los tanques."},
  {"id":10,"q":"El compresor normalmente deja de bombear (cut-out) a unos:","opts":["20 psi","60 psi","125 psi","300 psi"],"re":"El cut-out es cerca de 125 psi; el cut-in (reinicio) cerca de 100 psi."},
  {"id":11,"q":"La advertencia de presión baja debe encenderse antes de que la presión baje de:","opts":["10 psi","30 psi","60 psi","100 psi"],"re":"La advertencia de aire bajo (luz o zumbador) debe activarse antes de que la presión baje de 60 psi."},
  {"id":12,"q":"El manómetro de presión de suministro muestra:","opts":["El nivel de aceite del motor","La profundidad del dibujo de la llanta","Cuánta presión de aire hay en los tanques","El nivel de combustible"],"re":"El manómetro de suministro muestra cuánta presión de aire hay en los tanques."},
  {"id":13,"q":"Antes de conducir un sistema de aire doble, sube la presión a unos:","opts":["20-30 psi","Cualquier cantidad sirve","Más de 300 psi","El rango normal de 100-125 psi"],"re":"Sube al rango normal de operación (unos 100-125 psi) antes de conducir."},
  {"id":14,"q":"Un dispositivo wig-wag es:","opts":["Un brazo mecánico de advertencia de aire bajo que cae a la vista","Una ayuda de dirección","Un tipo de llanta","Un medidor de combustible"],"re":"El wig-wag es un brazo mecánico que baja para advertir de presión de aire baja."},
  {"id":15,"q":"El interruptor de luces de freno operado por aire:","opts":["Enciende las luces de freno cuando pisas el freno","Controla el claxon","Drena los tanques","Bombea aire"],"re":"Un interruptor operado por aire enciende las luces de freno al aplicar los frenos."},
  {"id":16,"q":"Si la presión de aire sigue bajando mientras conduces, debes:","opts":["Acelerar","Ignorarlo","Apagar el manómetro","Frenar y estacionarte con seguridad lo antes posible"],"re":"El aire bajo o que baja significa que los frenos pueden fallar; detente y estaciónate de inmediato."},
  {"id":17,"q":"La válvula de alivio de seguridad del primer tanque suele abrir a unos:","opts":["20 psi","60 psi","150 psi","500 psi"],"re":"La válvula de alivio protege el tanque y suele abrir cerca de 150 psi."},
  {"id":18,"q":"Los frenos de estacionamiento (de resorte) se mantienen sueltos por:","opts":["La presión de aire","Resortes","El aceite del motor","La gravedad"],"re":"El aire retiene los resortes; al soltar el aire, los resortes aplican los frenos."},
  {"id":19,"q":"Cuando se pierde la presión de aire, los frenos de resorte:","opts":["Quedan sueltos","Bombean los tanques","Tocan el claxon","Se aplican automáticamente"],"re":"Al bajar la presión, los resortes aplican los frenos — tu sistema de parada de emergencia."},
  {"id":20,"q":"El botón de control del freno de estacionamiento es:","opts":["Un botón redondo rojo","Un botón cuadrado azul","Un botón amarillo en forma de diamante","Un botón circular verde"],"re":"El botón amarillo en forma de diamante aplica (jalar) y suelta (empujar) los frenos de estacionamiento."},
  {"id":21,"q":"Para soltar los frenos de estacionamiento:","opts":["Jalas el botón","Empujas el botón","Pisas la válvula de pie","Aceleras el motor"],"re":"Empuja el botón amarillo para soltar; jálalo para aplicar los frenos de estacionamiento."},
  {"id":22,"q":"NO debes aplicar el freno de estacionamiento cuando:","opts":["Estás en una pendiente","Estás en terreno plano","El motor está apagado","Los frenos están muy calientes o mojados y podrían congelarse"],"re":"Los frenos calientes pueden dañarse y los mojados congelarse; déjalos enfriar o secar cuando sea posible."},
  {"id":23,"q":"Los frenos de resorte suelen aplicarse del todo cuando la presión baja a unos:","opts":["75 psi","20 a 45 psi","100 psi","Solo a 0 psi"],"re":"Los frenos de resorte se aplican entre unos 20 y 45 psi a medida que baja la presión."},
  {"id":24,"q":"Al estacionar un vehículo con frenos de resorte, debes:","opts":["Aplicar los frenos de estacionamiento (de resorte)","Dejarlo en marcha sin freno","Solo sostener el pedal","Confiar solo en los frenos del remolque"],"re":"Aplica los frenos de estacionamiento al estacionar; no confíes en sostener el pedal."},
  {"id":25,"q":"Aplicar los frenos de servicio cuando los de resorte ya están aplicados puede:","opts":["Mejorar el frenado","Combinar fuerzas y dañar piezas del freno","Enfriar los frenos","Ahorrar aire"],"re":"Aplicar el freno de servicio sobre los resortes puede ejercer demasiada fuerza; los sistemas modernos lo limitan."},
  {"id":26,"q":"En un sistema de aire doble, la presión debe subir de 85 a 100 psi en unos:","opts":["5 segundos","45 segundos","5 minutos","No importa"],"re":"La presión debe subir de 85 a 100 psi en unos 45 segundos en un sistema de aire doble."},
  {"id":27,"q":"Con el motor apagado y los frenos sueltos, la pérdida de aire en un vehículo simple debe ser menor a:","opts":["2 psi por minuto","10 psi por minuto","25 psi por minuto","Cualquier tasa sirve"],"re":"La fuga estática en un camión recto debe ser menor a 2 psi por minuto (3 en combinaciones)."},
  {"id":28,"q":"Con el motor apagado y los frenos aplicados, la pérdida de aire en un vehículo simple debe ser menor a:","opts":["3 psi por minuto","15 psi por minuto","30 psi por minuto","No hay límite"],"re":"Con los frenos aplicados, la fuga debe ser menor a 3 psi por minuto en un vehículo simple (4 en combinaciones)."},
  {"id":29,"q":"Para probar la advertencia de aire bajo:","opts":["Bombeas los frenos para bajar la presión y confirmas que la advertencia se enciende antes de 60 psi","Conduces rápido","Drenas todos los tanques","Aceleras el motor"],"re":"Con el motor apagado, agota aire; la advertencia debe encenderse antes de que la presión baje de 60 psi."},
  {"id":30,"q":"Si sigues agotando aire tras la advertencia, los frenos de resorte deben aplicarse a unos:","opts":["75 psi","20 a 45 psi","100 psi","5 psi"],"re":"Sigue bajando la presión; los frenos de resorte deben aplicarse entre unos 20 y 45 psi."},
  {"id":31,"q":"Para revisar el gobernador del compresor:","opts":["Nunca se revisa","Drenas todos los tanques","Subes hasta el cut-out, luego agotas aire hasta el cut-in","Quitas el manómetro"],"re":"Acelera hasta la presión de cut-out, luego agota los frenos hasta que el gobernador reactive el compresor (cut-in)."},
  {"id":32,"q":"Para revisar los ajustadores de holgura de leva en S, con los frenos sueltos:","opts":["Jalas fuerte cada uno — no debe moverse más de una pulgada aproximadamente","Los cortas","Giras el tambor","Les agregas aire"],"re":"Con el motor apagado y el freno de estacionamiento suelto, jala cada ajustador; más de una pulgada de juego indica que necesitan ajuste."},
  {"id":33,"q":"La razón más importante de las revisiones de frenos de aire es:","opts":["Perder el tiempo","Limpiar el camión","Ahorrar combustible","Asegurar que los frenos suban, retengan, adviertan y apliquen"],"re":"Las revisiones confirman que los frenos de aire suben, retienen, advierten y aplican bien antes de conducir."},
  {"id":34,"q":"Un tambor de freno NO debe tener grietas más largas que:","opts":["Cualquier grieta es aceptable","La mitad del ancho de la superficie de fricción","Todo el ancho del tambor","Las grietas nunca importan"],"re":"Las grietas más largas que la mitad del ancho de la superficie de fricción vuelven inseguro el tambor."},
  {"id":35,"q":"Los frenos de aire tardan más que los hidráulicos por:","opts":["El retardo del freno (brake lag) — el tiempo para que fluya el aire","La radio","Líquido más pesado","Llantas más grandes"],"re":"El aire tarda un momento en viajar y subir (brake lag), lo que se suma a la distancia total de frenado."},
  {"id":36,"q":"A 55 mph, ¿cuánto agrega el retardo del freno a la distancia de frenado?","opts":["0 pies","Unos 32 pies","Unos 300 pies","Cerca de una milla"],"re":"El brake lag agrega unos 32 pies a 55 mph, además de la percepción, la reacción y el frenado."},
  {"id":37,"q":"La forma más segura de hacer una parada normal es:","opts":["Dar un golpe al pedal","Aplicar presión constante y controlada","Bombear el pedal rápido","Usar el freno de estacionamiento"],"re":"El frenado constante y controlado te detiene suavemente sin bloquear las ruedas."},
  {"id":38,"q":"En una bajada larga, el método correcto de frenado es:","opts":["Mantener los frenos pisados todo el camino","Usar el freno de estacionamiento","Ir en neutral por inercia","Elegir una marcha baja y usar frenado ligero, constante o por tandas (snub)"],"re":"Una marcha baja más frenado ligero o snub evita que los frenos se sobrecalienten y pierdan eficacia."},
  {"id":39,"q":"El frenado por golpes (stab braking) se usa:","opts":["En cada parada","Solo para estacionar","Solo en emergencia en vehículos sin ABS","Para ahorrar combustible"],"re":"El stab braking (aplicar a fondo, soltar al bloquearse, reaplicar) es una técnica de emergencia para vehículos sin ABS."},
  {"id":40,"q":"El desvanecimiento del freno (brake fade) se debe a:","opts":["Frenos fríos","Sobrecalentar los frenos por abusar de ellos","Forros nuevos","Cargas ligeras"],"re":"El calor excesivo por mantener los frenos pisados en la bajada reduce la potencia de frenado (fade)."},
  {"id":41,"q":"Si tu vehículo tiene ABS y debes detenerte rápido, debes:","opts":["Bombear el pedal","Evitar frenar","Frenar firme y conservar el control de la dirección","Usar solo el freno de estacionamiento"],"re":"Con ABS, aplica presión firme y constante; el sistema evita el bloqueo y conservas la dirección."},
  {"id":42,"q":"Bombear los frenos (pisar y soltar repetidamente) en una bajada puede:","opts":["Subir el aire","Enfriar los frenos","Mejorar el control","Gastar el aire más rápido de lo que el compresor lo repone"],"re":"Bombear los frenos en la bajada gasta aire; la presión puede bajar hasta que fallen los frenos."},
  {"id":43,"q":"Debes drenar la humedad de los tanques de aire:","opts":["A diario, o confiar en los drenajes automáticos","Una vez al año","Nunca","Solo en verano"],"re":"Drena agua y aceite a diario; la humedad puede reducir el frenado y congelarse en frío."},
  {"id":44,"q":"Un evaporador de alcohol sirve para:","opts":["Limpiar las ventanas","Reducir el riesgo de hielo en el sistema de aire en clima frío","Aumentar la potencia del motor","Inflar las llantas"],"re":"El evaporador de alcohol introduce alcohol en el sistema de aire para evitar el hielo en clima frío."},
  {"id":45,"q":"En un sistema de aire doble, si falla un circuito, el otro:","opts":["También falla de inmediato","Bombea los tanques","Aún da algo de frenado, pero aumenta la distancia de frenado","Bloquea las ruedas"],"re":"El circuito restante sigue funcionando, pero tendrás menos frenado y mayor distancia de frenado."},
  {"id":46,"q":"El sistema antibloqueo (ABS):","opts":["Reemplaza los frenos normales","Bombea el aire","Garantiza una parada más corta siempre","Evita que las ruedas se bloqueen para que puedas dirigir"],"re":"El ABS evita el bloqueo de ruedas en un frenado fuerte para que conserves el control de la dirección."},
  {"id":47,"q":"Si la luz de falla del ABS queda encendida, tu vehículo:","opts":["No tiene frenos","Aún tiene frenos normales, solo sin ABS","Debe abandonarse","No puede frenar"],"re":"Aún tienes frenos normales; solo se pierde la función antibloqueo — repáralo."},
  {"id":48,"q":"Mantener los frenos pisados (presión ligera) en una bajada es:","opts":["Buena idea","Mala idea — los sobrecalienta y causa fade","Obligatorio por ley","La mejor técnica"],"re":"Arrastrar los frenos los sobrecalienta y causa fade; usa el freno de motor y el snubbing."},
  {"id":49,"q":"Tras una parada fuerte o una bajada larga, los frenos de resorte/estacionamiento deben:","opts":["Dejarse enfriar antes de aplicarse, cuando sea posible","Aplicarse de inmediato muy calientes","Quitarse","Mojarse con agua fría"],"re":"Aplicar frenos muy calientes puede dañarlos o, si están mojados, congelarlos; déjalos enfriar cuando puedas."},
  {"id":50,"q":"La advertencia de aire bajo te dice:","opts":["Que aceleres","Que la radio está encendida","Que el combustible está bajo","Que la presión de aire está peligrosamente baja y los frenos pueden fallar"],"re":"Una advertencia de aire bajo significa detenerse y estacionarse con seguridad — tu capacidad de frenado está en riesgo."}
];
